const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let table;

try {
  table = JSON.parse(cleaned);

  if (!Array.isArray(table.columns) || !Array.isArray(table.rows)) {
    throw new Error("Invalid table format");
  }
} catch (error) {
  table = {
    title: "Demo Study Table",
    description: "A fallback illustration table for Study Aura.",
    columns: [
      { key: "term", label: "Term" },
      { key: "meaning", label: "Meaning" },
      { key: "example", label: "Example" }
    ],
    rows: [
      {
        term: "Dolphin",
        meaning: "An intelligent marine mammal",
        example: "Uses echolocation to navigate"
      },
      {
        term: "Coral Reef",
        meaning: "A marine ecosystem built by coral polyps",
        example: "Provides habitat for many ocean species"
      }
    ]
  };
}

const columns = table.columns.map((column) => ({
  key: String(column.key || "column"),
  label: String(column.label || column.key || "Column")
}));

const rows = table.rows.map((row) => {
  const normalizedRow = {};

  for (const column of columns) {
    normalizedRow[column.key] = String(row[column.key] || "");
  }

  return normalizedRow;
});

return [
  {
    json: {
      table: {
        title: String(table.title || "Study Aura Table"),
        description: String(table.description || "Generated study table."),
        columns,
        rows
      },
      fallback: false
    }
  }
];

